import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_updated',
      ]);
      expect(prefs.createdAt).toBeInstanceOf(Date);
      expect(prefs.updatedAt).toBeInstanceOf(Date);
    });

    it('should create preferences with custom values', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        emailFrequency: 'daily_digest',
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('daily_digest');
      expect(prefs.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });

    it('should return preferences for a known user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailEnabled: false });
      expect(updated.emailEnabled).toBe(false);
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        emailFrequency: 'weekly_digest',
      });
      expect(updated.emailFrequency).toBe('weekly_digest');
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });
      expect(updated.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw if no preferences exist for user', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { emailEnabled: false }),
      ).toThrow('No preferences found for user: nonexistent');
    });

    it('should update the updatedAt timestamp', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      const originalUpdatedAt = prefs.updatedAt;

      const updated = service.updatePreferences('user-1', { emailEnabled: false });
      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(
        originalUpdatedAt.getTime(),
      );
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false for nonexistent user', () => {
      expect(service.deletePreferences('nonexistent')).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'user_welcome')).toBe(false);
    });

    it('should return true for subscribed category even with limited subscription', () => {
      service.createPreferences({
        userId: 'user-1',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email disabled regardless of categories', () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
        subscribedCategories: ['order_confirmation', 'order_status_update', 'user_welcome', 'user_updated'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create preferences if they do not exist', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
    });

    it('should return existing preferences without creating new ones', () => {
      service.createPreferences({
        userId: 'user-1',
        emailFrequency: 'weekly_digest',
      });

      const prefs = service.getOrCreatePreferences('user-1');
      expect(prefs.emailFrequency).toBe('weekly_digest');
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailNotificationAdapter;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailNotificationAdapter();
    notificationService.registerAdapter(emailAdapter);

    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send notification when user has no preferences', async () => {
    await eventBus.emit<OrderCreatedEvent>({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress notification when user has email disabled', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      emailEnabled: false,
    });

    await eventBus.emit<OrderCreatedEvent>({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      subscribedCategories: ['order_status_update'],
    });

    await eventBus.emit<OrderCreatedEvent>({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send notification when category is subscribed', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit<OrderCreatedEvent>({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should send welcome notification when user has default preferences', async () => {
    preferencesService.createPreferences({ userId: 'user-1' });

    await eventBus.emit<UserCreatedEvent>({
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotifications()[0]?.type).toBe('user_welcome');
  });

  it('should suppress welcome notification when user unsubscribed from user_welcome', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      subscribedCategories: ['order_confirmation', 'order_status_update'],
    });

    await eventBus.emit<UserCreatedEvent>({
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    expect(notificationService.getNotificationCount()).toBe(0);
  });
});

